let tareas = [];

function crearTarea(titulo, prioridad, descripcion) {
    const id = tareas.reduce((max, t) => t.id > max ? t.id : max, 0) + 1;

    return {
        id: id,
        titulo: titulo,
        prioridad: prioridad,
        descripcion: descripcion,
        completada: false
    };
}

function mostrarTarea(tarea) {
    const info = [
        `Título: ${tarea.titulo}`,
        `Prioridad: ${tarea.prioridad}`,
        `Descripción: ${tarea.descripcion}`,
        `Completada: ${tarea.completada}`
    ];
}

function agregarTarea(titulo, prioridad, descripcion) {
    tareas = [...tareas, crearTarea(titulo, prioridad, descripcion)];
}

function buscarTarea(id) {
    for (let i = 0; i < tareas.length; i++) {
        if (tareas[i].id === id) {
            return tareas[i];
        }
    }
    return undefined;
}

function completarTarea(id) {
    const tarea = buscarTarea(id);
    tarea && (tarea.completada = true);
}

function eliminarTarea(id) {
    const nuevas = [];
    for (let t of tareas) {
        if (t.id !== id) {
            nuevas.push(t);
        }
    }
    tareas = nuevas;
}

function copiarTarea(id) {
    const original = buscarTarea(id);

    if (original) {
        const copia = crearTarea(
            original.titulo + " copia",
            original.prioridad,
            original.descripcion
        );

        copia.completada = original.completada;
        tareas.push(copia);
    }
}

function filtrarTareas(estado) {
    const resultado = [];

    for (let tarea of tareas) {
        if (tarea.completada === estado) {
            resultado.push(tarea);
        }
    }

    return resultado;
}

function filtrarTareasPorPrioridad(prioridad) {
    const resultado = [];

    for (let tarea of tareas) {
        if (tarea.prioridad === prioridad) {
            resultado.push(tarea);
        }
    }

    return resultado;
}

function contarPorPrioridad() {
    const conteo = { alta: 0, media: 0, baja: 0 };

    for (let tarea of tareas) {
        if (conteo[tarea.prioridad] !== undefined) {
            conteo[tarea.prioridad]++;
        }
    }

    return conteo;
}

function ordenarTareasPorPrioridad() {
    const orden = { alta: 1, media: 2, baja: 3 };
    const copia = [...tareas];

    copia.sort((a, b) => orden[a.prioridad] - orden[b.prioridad]);

    return copia;
}

function buscarTareas(termino) {
    const texto = termino.toLowerCase();
    const resultados = [];

    for (let tarea of tareas) {
        const titulo = tarea.titulo.toLowerCase();
        const descripcion = tarea.descripcion ? tarea.descripcion.toLowerCase() : "";

        if (titulo.includes(texto) || descripcion.includes(texto)) {
            resultados.push(tarea);
        }
    }

    return resultados;
}

function validarTarea(tarea) {
    const errores = [];

    if (typeof tarea.titulo !== "string" || tarea.titulo.trim() === "") {
        errores.push("El título es requerido y debe ser texto.");
    }

    const prioridadesValidas = ["alta", "media", "baja"];

    if (!prioridadesValidas.includes(tarea.prioridad)) {
        errores.push("La prioridad debe ser 'alta', 'media' o 'baja'.");
    }

    return {
        esValida: errores.length === 0,
        errores: errores
    };
}